        <Route path="/recursos" component={Resources} />
        <Route path="/estafas" component={Scams} />
        <Route path="/trabaja-conmigo" component={WorkWithMe} />
        <Route component={NotFound} />
      </Switch>
    </QueryClientProvider>
  );
}

export default App;

