  res.setHeader("Access-Control-Allow-Methods", "POST, OPTIONS");
  res.setHeader("Access-Control-Allow-Headers", "Content-Type");

  if (req.method === "OPTIONS") {
    return res.status(204).end();
  }

  if (req.method !== "POST") {
    return res.status(405).json({ error: "Method Not Allowed" });
  }

  // TODO: Add rate limiting — use @upstash/ratelimit + @upstash/redis
  // Example: 5 requests per hour per IP to prevent abuse

  // Zod validation
  const parsed = bodySchema.safeParse(req.body);
  if (!parsed.success) {
    return res.status(400).json({ error: "Invalid input" });
  }
  const { email, score } = parsed.data;

  // 1. Add contact to Resend Audience
  if (AUDIENCE_ID) {
    try {
      await resend.contacts.create({
        email,
        audienceId: AUDIENCE_ID,
        unsubscribed: false,
      });
    } catch (err) {
      console.error("Resend audience error:", err instanceof Error ? err.message : String(err));
    }
  } else {
    console.warn("RESEND_AUDIENCE_ID is not set — skipping audience add");
  }

  // 2. Send Privacy Score email to the user
  try {
    await resend.emails.send({
      from: FROM_EMAIL,
      to: email,
      subject: `Tu Privacy Score: ${score}/100 — ${getCategoryLabel(score)}`,
      html: buildEmailHtml(score),
    });
  } catch (err) {
    console.error("Resend email send error:", err instanceof Error ? err.message : String(err));
    return res.status(500).json({ error: "Failed to send email" });
  }

  return res.status(200).json({ success: true });
}

